    tok := 0;
    if pos = 0 then tok := t0;
    if pos = 1 then tok := t1;
    if pos = 2 then tok := t2;
    if tok = 20 then
    begin
      val := pos;
      running := false
    end;
    pos := pos + 1;
    if pos >= 3 then
      running := false
  end;
  if val = 1 then
    writeln('PASS 5')
  else
    writeln('FAIL 5');

  writeln('DONE')
end.

