  check(var_index(TOK_VAR_A) = 0, 30);
  check(var_index(TOK_VAR_Z) = 25, 31);
  check(var_token(0) = TOK_VAR_A, 32);
  check(var_token(25) = TOK_VAR_Z, 33);

