  if tok = TOK_PLUS+8  then write('>');
  if tok = TOK_GE      then begin write('>'); write('=') end
end;

procedure print_variable(tok: integer);
var ch: char;
begin
  ch := chr(ord('A') + tok - TOK_VAR_A);
  write(ch)
end;

{ --- Self-test --- }

procedure check(ok: boolean; id: integer);
begin
  if ok then write('P') else write('F');
  writeln(id)
end;

begin
  init_keywords;

  { Keyword table }
  check(kw_len(0) = 3, 1);
  check(kw_len(1) = 5, 2);
  check(kw_len(3) = 2, 3);
  check(kw_len(7) = 6, 4);
  check(kw_len(9) = 2, 5);
  check(kw_char(0, 0) = 'L', 6);
  check(kw_char(0, 2) = 'T', 7);
  check(kw_char(1, 0) = 'P', 8);
  check(kw_char(5, 0) = 'G', 9);

