program BasicTokens;
{ COR24 BASIC v1 — Token definitions, keyword table, and detokenizer. }

const
  FIRST_KEYWORD = 128;
  LAST_KEYWORD  = 151;
  TOK_PLUS  = 160;
  TOK_GE    = 169;
  TOK_VAR_A = 192;
  TOK_VAR_Z = 217;
  TOK_INT   = 224;
  TOK_STR   = 225;
  KW_WIDTH  = 8;
  NUM_KW    = 24;

var
  kw_table: array[0..191] of char;

procedure kw_set(idx: integer; s0, s1, s2, s3, s4, s5, s6, s7: char);
var base: integer;
begin
  base := idx * KW_WIDTH;
  kw_table[base]     := s0;
  kw_table[base + 1] := s1;
  kw_table[base + 2] := s2;
  kw_table[base + 3] := s3;
  kw_table[base + 4] := s4;
  kw_table[base + 5] := s5;
  kw_table[base + 6] := s6;
  kw_table[base + 7] := s7
end;

procedure init_keywords;
begin
  kw_set( 0, 'L','E','T',' ',' ',' ',' ',' ');
